18	/// Shared handle passed to the control listener and polled by tray/UI.
19	///
20	/// All fields are cheap to clone (Arc-wrapped).
21	#[derive(Clone)]
22	pub struct DaemonHandle {
23	    /// Macro dispatcher shared with the pipeline; used to push profile updates.
24	    pub dispatcher: Arc<Dispatcher>,
25	    /// Set true to suppress audio processing. The pipeline thread checks this
26	    /// on each frame and skips wake/VAD/STT while muted.
27	    pub muted: Arc<AtomicBool>,
28	    /// Name of the currently active profile, updated on every SwitchProfile.
29	    pub active_profile: Arc<RwLock<Option<String>>>,
30	    /// Set true while the wake-word listen window is open (written by coordinator).
31	    pub listening: Arc<AtomicBool>,
32	    /// Set true while PTT is held (written by coordinator).
33	    pub recording: Arc<AtomicBool>,
34	    /// Channel to the running pipeline coordinator for live runtime changes.
35	    /// `None` when the pipeline is not running (e.g. during unit tests).
36	    pub runtime_cmd_tx: Option<Arc<std::sync::mpsc::Sender<RuntimeCommand>>>,
37	    /// Currently cached activation mode; updated by the SetMode handler before
38	    /// forwarding to the coordinator so Status responses stay coherent.
39	    pub active_mode: Arc<RwLock<ActivationMode>>,
40	}
