7	/// Send a command to the running daemon via the UDS socket.
8	pub fn send_command(req: ControlRequest) -> Result<ControlResponse> {
9	    let socket_path = get_socket_path()?;
10	
11	    let mut stream = UnixStream::connect(&socket_path)
12	        .with_context(|| format!("Failed to connect to daemon at {}. Is it running?", socket_path.display()))?;
13	
14	    let req_json = serde_json::to_string(&req)?;
15	    stream.write_all(req_json.as_bytes())?;
16	    stream.write_all(b"\n")?;
17	
18	    let mut reader = BufReader::new(stream);
19	    let mut response_line = String::new();
20	    reader.read_line(&mut response_line)?;
21	
22	    let response: ControlResponse = serde_json::from_str(&response_line)
23	        .with_context(|| format!("Failed to parse daemon response: {response_line}"))?;
24	
25	    Ok(response)
26	}
