27	/// Simulates the coordinator's per-frame try_recv drain against a Dispatcher.
28	/// Returns the number of commands processed.
29	fn drain_into_dispatcher(rx: &mpsc::Receiver<RuntimeCommand>, dispatcher: &Arc<Dispatcher>) -> usize {
30	    let mut count = 0;
31	    while let Ok(cmd) = rx.try_recv() {
32	        match cmd {
33	            RuntimeCommand::SetThreshold(t) => {
34	                dispatcher.update_threshold(t);
35	                count += 1;
36	            }
37	            RuntimeCommand::SetMode(_m) => {
38	                count += 1;
39	            }
40	            RuntimeCommand::SetInputDevice(_) | RuntimeCommand::SetPttBinding(_) | RuntimeCommand::ReloadConfig => {
41	                count += 1;
42	            }
43	        }
44	    }
45	    count
46	}
